class EventEmitter {
  #handlers = {};
  on(event, fn) { (this.#handlers[event] ??= []).push(fn); }
  emit(event, ...args) { (this.#handlers[event] ?? []).forEach(fn => fn(...args)); }
}

async function retryable(fn, attempts = 3) {
  for (let i = 0; i < attempts; i++) {
    try { return await fn(); }
    catch (err) { if (i === attempts - 1) throw err; }
  }
}

