// adapters/file-storage.js — Node.js RUNTIME adapter
import { StoragePort } from '../ports/storage.js';
import { readFile, writeFile, unlink } from 'fs/promises'; // runtime
import { join } from 'path';                               // runtime

export class FileStorage extends StoragePort {
  #dir;
  constructor(dir) { super(); this.#dir = dir; }
  async save(key, value) { await writeFile(join(this.#dir, key), JSON.stringify(value)); }
  async load(key) { return JSON.parse(await readFile(join(this.#dir, key), 'utf8')); }
  async delete(key) { await unlink(join(this.#dir, key)); }
}

// adapters/memory-storage.js — pure JavaScript adapter (for tests)
import { StoragePort } from '../ports/storage.js';
export class MemoryStorage extends StoragePort {
  #map = new Map();
  async save(key, value) { this.#map.set(key, value); }
  async load(key) { return this.#map.get(key) ?? null; }
  async delete(key) { this.#map.delete(key); }
}

