// ✅ Know what the framework adds vs what the runtime provides
// Raw Node.js request object: req.headers, req.method, req.url, req (as readable stream)
// Express ADDS: req.body (via body parser), req.params, req.query, res.json, res.send
const http = require('http');
const server = http.createServer((req, res) => {
  // Raw runtime: must parse body manually
  let body = '';
  req.on('data', chunk => { body += chunk; });
  req.on('end', () => {
    const parsed = JSON.parse(body);
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ received: parsed }));
  });
});

